16	const PROCESSING_FEE = 5;
17	const DEFAULT_BASE_PREMIUM = 100;
18	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const CURSE_SURCHARGE_RATE = 0.5;
27	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
28	
29	function basePremiumFor(item: Item): number {
30	  const base = BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
31	  let premium = base;
32	  if (item.enchantment === 5) {
33	    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
34	  }
35	  if (item.cursed) {
36	    premium += base * CURSE_SURCHARGE_RATE;
37	  }
38	  return premium;
39	}
40	
41	const BLOCK_SIZE = 3;
42	const BLOCK_PREMIUM = 60;
43	
44	function groupByType(items: Item[]): Map<string, Item[]> {
45	  const groups = new Map<string, Item[]>();
46	  for (const item of items) {
47	    const group = groups.get(item.type) ?? [];
48	    group.push(item);
49	    groups.set(item.type, group);
50	  }
51	  return groups;
52	}
53	
54	function basePremiumForGroup(group: Item[]): number {
55	  if (group.length === BLOCK_SIZE) {
56	    return BLOCK_PREMIUM;
57	  }
58	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
59	}
60	
61	export function quote(input: QuoteInput): QuoteResult {
62	  const groups = [...groupByType(input.items).values()];
63	  const basePremium = groups.reduce(
64	    (sum, group) => sum + basePremiumForGroup(group),
65	    0,
66	  );
67	
68	  return { premium: basePremium + PROCESSING_FEE };
69	}
